import {{ Injectable }} from '@nestjs/common';
import {{ BackupService }} from './models/backup.model';
import {{ BackupServiceRepository }} from './repositories/backup.repository';

@Injectable()
export class BackupServiceService {{
  constructor(
    private readonly repository: BackupServiceRepository,
  ) {{}}

  async findAll(): Promise<BackupService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<BackupService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<BackupService>): Promise<BackupService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<BackupService>): Promise<BackupService> {{
    return this.repository.update(id, data);
  }}
}}
